function solve(grid, k) {
    const m = grid.length;
    const n = grid[0].length;
    const teleport = new Array(m);
    for (let i = 0; i < m; i++) {
        teleport[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            teleport[i][j] = [];
            const val = grid[i][j];
            for (let x = 0; x < m; x++) {
                for (let y = 0; y < n; y++) {
                    if (grid[x][y] <= val) {
                        teleport[i][j].push([x, y]);
                    }
                }
            }
        }
    }

    const INF = Infinity;
    const dist = new Array(m);
    for (let i = 0; i < m; i++) {
        dist[i] = new Array(n);
        for (let j = 0; j < n; j++) {
            dist[i][j] = new Array(k + 1).fill(INF);
        }
    }
    dist[0][0][0] = 0;

    class MinHeap {
        constructor() {
            this.heap = [];
        }

        push(value) {
            this.heap.push(value);
            this.bubbleUp(this.heap.length - 1);
        }

        pop() {
            if (this.heap.length === 0) return null;
            const popped = this.heap[0];
            this.heap[0] = this.heap[this.heap.length - 1];
            this.heap.pop();
            this.bubbleDown(0);
            return popped;
        }

        bubbleUp(index) {
            while (index > 0) {
                const parent = Math.floor((index - 1) / 2);
                if (this.heap[index][0] < this.heap[parent][0]) {
                    [this.heap[index], this.heap[parent]] = [this.heap[parent], this.heap[index]];
                    index = parent;
                } else {
                    break;
                }
            }
        }

        bubbleDown(index) {
            const length = this.heap.length;
            while (index < length) {
                const left = 2 * index + 1;
                const right = 2 * index + 2;
                let smallest = index;
                if (left < length && this.heap[left][0] < this.heap[smallest][0]) {
                    smallest = left;
                }
                if (right < length && this.heap[right][0] < this.heap[smallest][0]) {
                    smallest = right;
                }
                if (smallest !== index) {
                    [this.heap[index], this.heap[smallest]] = [this.heap[smallest], this.heap[index]];
                    index = smallest;
                } else {
                    break;
                }
            }
        }
    }

    const heap = new MinHeap();
    heap.push([0, 0, 0, 0]);

    while (heap.heap.length > 0) {
        const [cost, i, j, t] = heap.pop();
        if (cost > dist[i][j][t]) continue;

        if (i === m - 1 && j === n - 1) {
            return cost;
        }

        const directions = [[0, 1], [1, 0]];
        for (const [dx, dy] of directions) {
            const ni = i + dx;
            const nj = j + dy;
            if (ni < m && nj < n) {
                const new_cost = cost + grid[ni][nj];
                if (new_cost < dist[ni][nj][t]) {
                    dist[ni][nj][t] = new_cost;
                    heap.push([new_cost, ni, nj, t]);
                }
            }
        }

        if (t < k) {
            for (const [x, y] of teleport[i][j]) {
                const new_t = t + 1;
                if (cost < dist[x][y][new_t]) {
                    dist[x][y][new_t] = cost;
                    heap.push([cost, x, y, new_t]);
                }
            }
        }
    }

    return -1;
}
